@app.route('/oauth/token', methods=['POST'])
def create_token():
    grant_type = request.form.get('grant_type')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')
    username = request.form.get('username')
    password = request.form.get('password')
    scope = request.form.get('scope', 'read')
    
    if grant_type != 'password':
        return jsonify({
            'error': 'unsupported_grant_type',
            'error_description': 'Only password grant type is supported'
        }), 400
    
    if not all([client_id, client_secret, username, password]):
        return jsonify({
            'error': 'invalid_request',
            'error_description': 'Missing required parameters'
        }), 400
    
    if client_secret != 'secret' or password != 'password':
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Invalid client credentials or user credentials'
        }), 401
    
    token = secrets.token_urlsafe(32)
    expires_at = datetime.utcnow().replace(microsecond=0)
    from datetime import timedelta
    expires_at = expires_at + timedelta(hours=1)
    
    db = get_db()
    db.execute(
        'INSERT INTO access_tokens (token, user_id, client_id, scope, expires_at) VALUES (?, ?, ?, ?, ?)',
        (token, username, client_id, scope, expires_at)
    )
    db.commit()
    db.close()
    
    return jsonify({
        'access_token': token,
        'token_type': 'Bearer',
        'expires_in': 3600,
        'scope': scope
    })

@app.route('/oauth/revoke', methods=['POST'])
def revoke_token():
    token = request.form.get('token')
    
    if not token:
        return jsonify({
            'error': 'invalid_request',
            'error_description': 'Token parameter is required'
        }), 400
    
    db = get_db()
    db.execute('DELETE FROM access_tokens WHERE token = ?', (token,))
    db.commit()
    db.close()
    
    return jsonify({'message': 'Token revoked successfully'})

@app.route('/oauth/introspect', methods=['POST'])
def introspect_token():
    token = request.form.get('token')
    
    if not token:
        return jsonify({'active': False})
    
    token_info = validate_token(token)
    
    if not token_info['valid']:
        return jsonify({'active': False})
    
    return jsonify({
        'active': True,
        'user_id': token_info['user_id'],
        'client_id': token_info['client_id'],
        'scope': token_info['scope'],
        'exp': token_info['expires_at']
    })

